import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useParams, useHistory } from 'react-router-dom';
import { Form, Button, Container } from 'react-bootstrap';

function EditEmployee() {
  const { id } = useParams();
  const [name, setName] = useState('');
  const [position, setPosition] = useState('');
  const [department, setDepartment] = useState('');
  const history = useHistory();

  useEffect(() => {
    axios.get(`/api/employees/${id}`)
      .then(response => {
        setName(response.data.name);
        setPosition(response.data.position);
        setDepartment(response.data.department);
      })
      .catch(error => {
        console.error('There was an error fetching the employee!', error);
      });
  }, [id]);

  const handleSubmit = (e) => {
    e.preventDefault();

    axios.patch(`/api/employees/${id}`, { name, position, department })
      .then(response => {
        history.push('/employees');
      })
      .catch(error => {
        console.error('There was an error updating the employee!', error);
      });
  };

  return (
    <Container className="mt-5 text-white">
      <h1>Edit Employee</h1>
      <Form onSubmit={handleSubmit}>
        <Form.Group>
          <Form.Label>Name</Form.Label>
          <Form.Control type="text" value={name} onChange={(e) => setName(e.target.value)} required />
        </Form.Group>
        <Form.Group>
          <Form.Label>Position</Form.Label>
          <Form.Control type="text" value={position} onChange={(e) => setPosition(e.target.value)} required />
        </Form.Group>
        <Form.Group>
          <Form.Label>Department</Form.Label>
          <Form.Control type="text" value={department} onChange={(e) => setDepartment(e.target.value)} required />
        </Form.Group>
        <Button type="submit" className="btn btn-primary mt-3">Update Employee</Button>
      </Form>
    </Container>
  );
}

export default EditEmployee;
